import React from "react"

const getSizeStyle = (scale = 1.0) => {
  return {
    fontSize: `${2.5 * scale}mm`,
    width: `${90 * scale}mm`,
    height: `${54 * scale}mm`,
  }
}
const ADDITIONAL = [
  "user@example.com",
  "Tel: (01) 2345-6789",
  "Fax: (09) 8765-4321#0909",
  "M: +81-234-567-890",
  "統一編號：01234567",
].join("\n")
const CardContainer = (
  {
    name = "王大明",
    engName = "Daming, Wang",
    position = "無線網路最佳化實驗室\n行政助理",
    engPosition = "Admistrator Assistance",
    company = "某一家很厲害的有限公司",
    engCompany = "Useful Co. Ltd.",
    address = "天龍國龍山市養鱒路三段礎幽街\n135 號 7 樓",
    additional = ADDITIONAL,
    scale,
    ...props
  },
  ref
) => {
  const extra = scale
    ? {
        style: getSizeStyle(scale),
      }
    : {}
  return (
    <div className="card-wrapper" {...props}>
      <div className="card-container" {...extra} ref={ref}>
        <div className="card-self">
          <p>{name}</p>
          <p>{engName}</p>
          <p>{position}</p>
          <p>{engPosition}</p>
        </div>
        <div className="card-detail">
          <h1>{engCompany}</h1>
          <h2>{company}</h2>
          <address className="addr">
            <p>{address}</p>
            {additional?.split(/\r?\n/).map(v => (
              <p key={v}>{v}</p>
            ))}
          </address>
        </div>
      </div>
    </div>
  )
}

export default React.forwardRef(CardContainer)
export { getSizeStyle }
