import React, { useEffect, useRef, useState } from "react"
import { Helmet } from "react-helmet"
import { graphql, useStaticQuery, withPrefix } from "gatsby"
import Img from "gatsby-image"
import CardContainer from "../../components/card/cardLayout"
import cardCss from "!raw-loader!sass-loader!../../css/business-card.scss"

import dom2Image from "dom-to-image"

import SocialMedia from "../../components/social-media"
import mdDesc from "!raw-loader!../../markdown/business-card.md"
import Markdown from "react-markdown"
import siteData from "../../datasheet/business-card.yml"
import SEO from "../../components/seo"

import { map } from "lodash"

import {
  Button,
  Chip,
  CircularProgress,
  Collapse,
  FormControlLabel,
  IconButton,
  NoSsr,
  Switch,
  TextField,
} from "@material-ui/core"

import { withStyles } from "@material-ui/core"
import { forEach, values } from "lodash"

// import "@google/model-viewer/dist/model-viewer"  // SSR failed.

const BgIconBtn = withStyles(theme => {
  return {
    root: {
      border: "#2223 solid",
      boxShadow: "0 0 15px 2px #2222",
      boxSizing: "border-box",
      margin: "0.5rem",
    },
  }
})(IconButton)

const WChip = withStyles(theme => {
  return {
    outlined: {
      border: "#2228 solid 2px",
      color: "#444",
      margin: "0.5rem",
    },
  }
})(Chip)

const useHandleState = (init, delay = 500) => {
  const [state, setState] = useState(init)
  let timer = null
  const handleEvent = e => {
    const { target } = e
    if (timer) {
      clearTimeout(timer)
    }
    timer = setTimeout(() => {
      setState(target.value)
    }, delay)
  }
  return [state, setState, handleEvent]
}

const ScaleController = ({ scale, setScale, ...props }) => {
  const ScaleBtn = ({ text, useValue, ...props }) => {
    return (
      <BgIconBtn
        onClick={e => setScale(useValue || Number(text))}
        style={{
          borderColor:
            !useValue && scale === Number(text) ? "rgb(180, 56, 91)" : "#2223",
        }}
        {...props}
      >
        <div
          style={{
            width: 24,
            height: 24,
            fontSize: "13px",
            fontWeight: "700",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
          }}
        >
          {text}×
        </div>
      </BgIconBtn>
    )
  }
  return (
    <div className="scale-controller">
      <ScaleBtn
        text="-.1"
        useValue={v => parseFloat((v - 0.1).toFixed(1))}
        disabled={Boolean(scale <= 0.1)}
      />
      <ScaleBtn text="1" />
      <ScaleBtn text="2" />
      <ScaleBtn text="3" />
      <ScaleBtn text="+.1" useValue={v => parseFloat((v + 0.1).toFixed(1))} />
    </div>
  )
}
const ScaleLabel = ({ scale, ...props }) => {
  return (
    <div className="scale-label">
      <span>Scale: </span>
      <span>{scale}×</span>
    </div>
  )
}

const Header = props => {
  const data = useStaticQuery(graphql`
    query {
      fileName: file(relativePath: { eq: "showcase/card-sample.png" }) {
        childImageSharp {
          fluid(maxWidth: 2560) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
    }
  `)
  const chips = [
    "Business Card",
    "Minimal Design",
    "3D Model",
    "Printable Content",
    "And more...",
  ]
  return (
    <header>
      <div className="header-wrapper">
        <h1>Business Card Example</h1>
        <p className="landmark" role="banner">
          Try this business card. It won't hurt.
        </p>
        <div style={{ textAlign: "center", margin: "1rem 2rem" }}>
          {chips.map(v => (
            <WChip label={v} key={`c-${v}`} variant="outlined" />
          ))}
        </div>
      </div>
      {data?.fileName?.childImageSharp?.fluid && (
        <Img fluid={data?.fileName?.childImageSharp?.fluid}></Img>
      )}
    </header>
  )
}

const EntryPage = props => {
  const cardRef = useRef(null)
  const [cardImg, setCardImage] = useState("")
  const [updater, setUpdater] = useState(0)
  const [updating, setUpdating] = useState(true)
  const [showForm, setShowForm] = useState(true)
  const [urlParsed, setUrlParsed] = useState(false)
  const [sharingUrl, setSharingUrl] = useState("")

  const [imageSize, , handleImageSize] = useHandleState(1024)
  const [name, setName, nameHandle] = useHandleState("金乘五")
  const [engName, setEngName, engNameHandle] = useHandleState("Mutif, King")
  const [position, setPosition, positionHandle] = useHandleState(
    "資深副總督\n設計人"
  )
  const [engPosition, setEngPosition, engPositionHandle] = useHandleState(
    "Gun-Tank,\nGolden Wind Experience Squad"
  )
  const [company, setCompany, companyHandle] = useHandleState(
    "清英社馬企業有限公司"
  )
  const [engCompany, setEngCompany, engCompanyHandle] = useHandleState(
    "WASD Co. Ltd."
  )
  const [address, setAddress, addressHandle] = useHandleState(
    "台北市南港區研究院路二段 00 號 \n比較大樓 104E"
  )
  const [additional, setAdditional, additionalHandle] = useHandleState(
    [
      "user@example.com",
      "Tel: (01) 2345-6789",
      "Fax: (09) 8765-4321#0909",
      "M: +81-234-567-890",
      "統一編號：01234567",
    ].join("\n")
  )
  const packParams = {
    name,
    engName,
    position,
    engPosition,
    company,
    engCompany,
    address,
    additional,
  }
  const packSetParams = {
    name: setName,
    engName: setEngName,
    position: setPosition,
    engPosition: setEngPosition,
    company: setCompany,
    engCompany: setEngCompany,
    address: setAddress,
    additional: setAdditional,
  }

  const formData = {
    "Basic Information": {
      Name: {
        value: name,
        handle: nameHandle,
      },
      "English Name": {
        value: engName,
        handle: engNameHandle,
      },
      Position: {
        value: position,
        handle: positionHandle,
        multiline: true,
      },
      "English Position": {
        value: engPosition,
        handle: engPositionHandle,
        multiline: true,
      },
    },
    "Detail Information": {
      Company: {
        value: company,
        handle: companyHandle,
        multiline: true,
      },
      "English Company": {
        value: engCompany,
        handle: engCompanyHandle,
        multiline: true,
      },
      Address: {
        value: address,
        handle: addressHandle,
        multiline: true,
      },
      Additional: {
        value: additional,
        handle: additionalHandle,
        multiline: true,
      },
    },
  }
  const [scale, setScale] = useHandleState(2.0)
  const handleUpdateImageClick = e => {
    setUpdater(pre => pre + 1)
  }

  // Update Image Data using "Dom 2 Image"
  useEffect(() => {
    setUpdating(true)
    const callback = setTimeout(() => {
      const targetWidth = imageSize
      const w = cardRef.current.offsetWidth
      const h = cardRef.current.offsetHeight
      const scale = targetWidth / w

      dom2Image
        .toPng(cardRef.current, {
          width: w * scale,
          height: h * scale,
          bgcolor: "white",
          style: {
            transform: `scale(${scale})`,
            transformOrigin: "top left",
          },
        })
        .then(function (dataUrl) {
          const card = document.querySelector("model-viewer#card-model")
          let material = card?.model?.materials[0]
          if (material) {
            material.pbrMetallicRoughness[
              "baseColorTexture"
            ].texture.source.setURI(dataUrl)
          } else {
            console.error("Model material not found!!")
          }
          setCardImage(dataUrl)
        })
        .catch(function (error) {
          console.error("oops, something went wrong!", error)
        })
        .finally(() => {
          setUpdating(false)
        })
    }, 100)
    return () => clearTimeout(callback)
  }, [cardRef, updater, imageSize, setUpdating])

  // Update URL search into state on first load
  useEffect(() => {
    const searchParams = new URLSearchParams(window.location.search)
    forEach(packSetParams, (setFunc, key) => {
      if (searchParams.has(key)) {
        setFunc(searchParams.get(key))
      }
    })
    setUrlParsed(true)
  }, [setUrlParsed])

  // Update sharing URL base on state (timeout?)
  useEffect(() => {
    let pars = new URLSearchParams()
    forEach(packParams, (value, key) => {
      pars.append(key, value)
    })
    setSharingUrl(
      window.location.origin + window.location.pathname + "?" + pars.toString()
    )
  }, values(packParams))
  return (
    <>
      <SEO {...siteData.SEO} />
      <Helmet>
        <style>{cardCss}</style>
        <style>
          {`body{background-image: url(${withPrefix('/BG/background.webp')});}`}
        </style>
        <script
          src="https://unpkg.com/focus-visible@5.1.0/dist/focus-visible.js"
          defer
        />
        <script
          type="module"
          src="https://unpkg.com/@google/model-viewer/dist/model-viewer.min.js"
        ></script>
      </Helmet>
      <nav>
        <ul>
          <li>
            <a href={withPrefix("/")}>Home</a>
          </li>
          <li>
            <a href={withPrefix("/symbols/")}>Symbols</a>
          </li>
          <li>
            <a href={withPrefix("/gradient-wallpaper/")}>Gradient</a>
          </li>
          <li>
            <a href={withPrefix("/screen")}>Screen</a>
          </li>
        </ul>
      </nav>
      <Header />
      <div className="container">
        <ScaleLabel scale={scale}></ScaleLabel>
        <ScaleController scale={scale} setScale={setScale}></ScaleController>
        <CardContainer
          // {...cardData}
          ref={cardRef}
          scale={scale}
          {...packParams}
        />
        {scale <= 1.3 && (
          <p className="info">
            Warning! Small Scale might violate the minimum font size set in
            Browser. Do not use these size to create image data. Will not be
            affect in print mode.
          </p>
        )}
        <TextField
          label="Share Link"
          value={sharingUrl}
          id="sharingUrl"
          type="text"
          variant="outlined"
          onFocus={e => {
            e.preventDefault()
            const { target } = e
            target.focus()
            target.setSelectionRange(0, target.value.length)
            // Need Refactor
          }}
          color="secondary"
        />
        <h2 style={{ textAlign: "center" }}>
          {/* Data Form<br/> */}
          <FormControlLabel
            value="Show Form"
            control={
              <Switch
                checked={showForm}
                onChange={e => {
                  setShowForm(e.target.checked)
                }}
                color="secondary"
              />
            }
            label="Show Form"
            labelPlacement="bottom"
          />
        </h2>
        {/* Form Area */}
        <Collapse in={showForm}>
          <p className="info">
            Card Data will be changed immediately after these forms. While the
            image data below will not change unless you press "update image"
            button or change the image size in 3D model box.
          </p>
          {urlParsed && (
            <form className="input-form">
              {map(formData, (fieldset, fieldName) => {
                return (
                  <fieldset key={`field-${fieldName}`}>
                    <legend>{fieldName}</legend>
                    {map(fieldset, ({ value, handle, ...options }, label) => {
                      return (
                        <TextField
                          label={label}
                          defaultValue={value}
                          id={label}
                          type="text"
                          variant="standard"
                          onChange={handle}
                          fullWidth
                          key={`input-${label}`}
                          color="secondary"
                          {...options}
                        />
                      )
                    })}
                  </fieldset>
                )
              })}
            </form>
          )}
        </Collapse>

        <h2>3D Preview</h2>
        <NoSsr>
          <model-viewer
            camera-controls
            id="card-model"
            src={withPrefix("/model/business-card-base.glb")}
            class="card-viewer"
          >
            <div className="image-preview">
              <label>Image Data</label>
              <img
                alt="Business Card Preview"
                width="200px"
                height="120px"
                src={cardImg}
                title="Image Data create from webpage"
              />
              <div className="update-btn">
                <Button
                  variant="contained"
                  // color="primary"
                  disabled={updating}
                  onClick={handleUpdateImageClick}
                  children="Update Image"
                />
                {updating && <CircularProgress size={24} />}
              </div>
              <TextField
                style={{
                  backgroundColor: "white",
                  marginTop: "1rem",
                  borderRadius: "10px",
                }}
                label="Image Size"
                defaultValue={imageSize}
                id="imageSize"
                type="number"
                variant="filled"
                size="small"
                onChange={handleImageSize}
              />
            </div>
          </model-viewer>
        </NoSsr>
        <Markdown className="description" children={mdDesc} />
      </div>

      <footer>
        <SocialMedia />
      </footer>
    </>
  )
}

export default EntryPage
